class Solution:
    def __init__(self):
        pass

    def solve(self, grid):
        self.grid = grid
        return self.backtrack(0, 0)

    def backtrack(self, row, col):
        if row == 9:
            return True
        if col == 9:
            return self.backtrack(row + 1, 0)

        if self.grid[row][col] != 0:
            return self.backtrack(row, col + 1)

        for num in range(1, 10):
            if self.isValid(row, col, num):
                self.grid[row][col] = num
                if self.backtrack(row, col + 1):
                    return True
                self.grid[row][col] = 0
        return False

    def isValid(self, row, col, num):
        # Check if the number can be placed in the current cell
        for i in range(9):
            if self.grid[row][i] == num or self.grid[i][col] == num:
                return False
        start_row = row - row % 3
        start_col = col - col % 3
        for i in range(3):
            for j in range(3):
                if self.grid[i + start_row][j + start_col] == num:
                    return False
        return True



