// Solution in C++
#include <iostream>
#include <vector>
#include <fstream>
#include <sstream>

using namespace std;

class Solution {
public:
bool solve(vector<vector<int>>& grid) {
    // Backtracking algorithm
    return backtrack(0, 0);
}

bool backtrack(int row, int col) {
    if (row == 9) {
        return true;
    }
    if (col == 9) {
        return backtrack(row + 1, 0);
    }

    if (grid[row][col] != 0) {
        return backtrack(row, col + 1);
    }

    for (int num = 1; num <= 9; ++num) {
        if (isValid(row, col, num)) {
            grid[row][col] = num;
            if (backtrack(row, col + 1)) {
                return true;
            }
            grid[row][col] = 0;
        }
    }
    return false;
}

bool isValid(int row, int col, int num) {
    // Check if the number can be placed in the current cell
    for (int i = 0; i < 9; ++i) {
        if (grid[row][i] == num || grid[i][col] == num) {
            return false;
        }
    }
    int start_row = row - row % 3;
    int start_col = col - col % 3;
    for (int i = 0; i < 3; ++i) {
        for (int j = 0; j < 3; ++j) {
            if (grid[i + start_row][j + start_col] == num) {
                return false;
            }
        }
    }
    return true;
}
};

int main() {
    Solution solution;
    vector<vector<int>> grid = {{5,3,0,0,7,0,0,0,0},{6,0,0,1,9,5,0,0,0},{0,9,8,0,0,0,0,6,0}};
    cout << (solution.solve(grid) ? "true" : "false") << endl;
    return 0;
}
